const FormGroup = ({ disabled = false, legendId, legendText, invalid = false, children, className, message = false, messageText = "", ...rest }) => {
	const prefix = usePrefix();
	const classNamesFieldset = classNames(`${prefix}--fieldset`, className);
	return /* @__PURE__ */ jsxs("fieldset", {
		disabled,
		...invalid && { "data-invalid": "" },
		className: classNamesFieldset,
		...rest,
		"aria-labelledby": rest["aria-labelledby"] || legendId,
		children: [
			/* @__PURE__ */ jsx("legend", {
				className: `${prefix}--label`,
				id: legendId || rest["aria-labelledby"],
				children: legendText
			}),
			children,
			message ? /* @__PURE__ */ jsx("div", {
				className: `${prefix}--form__requirements`,
				children: messageText
			}) : null
		]
	});
};
FormGroup.propTypes = {
	children: PropTypes.node,
	className: PropTypes.string,
	disabled: PropTypes.bool,
	invalid: PropTypes.bool,
	legendId: PropTypes.node,
	legendText: PropTypes.node.isRequired,
	message: PropTypes.bool,
	messageText: PropTypes.string
};
//#endregion
export { FormGroup as default };
